var TOKEN_URL = env.get('HYDRA_TOKEN_URL');
var CLIENT_ID = env.get('ORCE_NOTARY_CLIENT_ID');
var CLIENT_SECRET = env.get('ORCE_NOTARY_CLIENT_SECRET');

if (!TOKEN_URL || !CLIENT_ID || !CLIENT_SECRET) {
    node.error('audit checkpoint anchoring is not configured: HYDRA_TOKEN_URL, ORCE_NOTARY_CLIENT_ID and ORCE_NOTARY_CLIENT_SECRET are all required', msg);
    return null;
}

msg.url = TOKEN_URL;
msg.method = 'POST';
msg.headers = { 'Content-Type': 'application/x-www-form-urlencoded' };
msg.payload = 'grant_type=client_credentials'
    + '&client_id=' + encodeURIComponent(CLIENT_ID)
    + '&client_secret=' + encodeURIComponent(CLIENT_SECRET);
return msg;

if (msg.statusCode !== 200 || !msg.payload || !msg.payload.access_token) {
    node.error('Hydra refused the client_credentials grant: HTTP ' + msg.statusCode + ' ' + JSON.stringify(msg.payload), msg);
    return null;
}

// DCS_URL already carries the API base path (see the orce extraEnv in the
// Helm values); every DCS endpoint hangs off it.
var DCS_URL = env.get('DCS_URL');
if (!DCS_URL) {
    node.error('DCS_URL is not configured', msg);
    return null;
}

msg.method = 'GET';
msg.url = DCS_URL.replace(/\/$/, '') + '/pac/audit/checkpoint/head';
msg.headers = { 'Authorization': 'Bearer ' + msg.payload.access_token };
msg.payload = '';
return msg;

// 404 until the very first checkpoint is anchored - nothing to pin yet.
if (msg.statusCode === 404) {
    return null;
}
if (msg.statusCode === 401 || msg.statusCode === 403) {
    node.error('DCS rejected the system client: HTTP ' + msg.statusCode + '. Is dcs-orce-notary listed under systemClients in the DCS values?', msg);
    return null;
}
if (msg.statusCode !== 200) {
    node.warn('checkpoint head unavailable: HTTP ' + msg.statusCode);
    return null;
}

var head = msg.payload;
if (!head || typeof head.seq !== 'number' || !head.root) {
    node.warn('malformed checkpoint head, not pinning');
    return null;
}

// Re-pinning an unchanged head adds no evidence: the chain has not grown.
var last = flow.get('lastSeenSeq') || 0;
if (head.seq <= last) {
    return null;
}
flow.set('lastSeenSeq', head.seq);

msg.payload = {
    todo: 'PIN THIS PROPERLY - forward to an append-only sink outside this operator (notary, chain, counterparty). A debug node anchors nothing.',
    observed_at: new Date().toISOString(),
    seq: head.seq,
    root: head.root,
    prev_root: head.prev_root || null,
    leaf_count: head.leaf_count,
    created_at: head.created_at,
    tsa_timestamp: head.tsa_timestamp || null,
    timestamped_at: head.timestamped_at || null
};
return msg;
